
import {
  defineComponent,
  onMounted,
  provide,
  reactive,
  ref,
  toRefs,
  watch,
} from "vue";
import Framework from "../../components/admin/user/Framework.vue";
import TableUser from "../../components/admin/user/TableUser.vue";
import SearchUser from "../../components/admin/user/SearchUser.vue";
import UpdateUser from "../../components/admin/user/modal/UpdateUser.vue";
import AddUser from "./user/AddUser.vue";
import {
  getAllDept,
  getUserlist,
  postUpdateState,
  getUserList,
} from "../../server/http/api/admin";

import { init } from "./hooks/user_init";
export default defineComponent({
  components: {
    Framework,
    TableUser,
    SearchUser,
    UpdateUser,
    AddUser,
  },
  name: "User",
  setup() {
    let userArr: any = ref([]);
    let data: any = reactive({
      frames: [],
      // 原始用户数据
      userdata: [],
      // 处理后
      // userlist: [],

      query: {
        deptId: "",
        username: "",
        mobile: "",
        state: "",
      },
    });
    function search() {
      getUserlist(data.query).then((res: any) => {
        data.userdata = res.data.data;
      });
    }
    // 组织架构
    getAllDept().then((res: any) => {
      if (res.data.code === 200) {
        init(res.data.data);
        data.frames = res.data.data;
        // //console.log("组织架构", data.frames);
      }
    });

    // 初始化用户列表
    onMounted(() => {
      search();
    });
    // 获取用户列表
    getUserList().then((res: any) => {
      if (res.data.code === 200) {
        // //console.log("获取用户列表", res.data.data);
        res.data.data.map((item: any) => {
          userArr.value.push({
            label: `${item.name}(${item.workplace})`,
            value: item.userid,
          });
        });
      }
    });

    // 1检索用户列表
    // 1-1组织架构条件
    let selectedClick = function (id: number[]) {
      data.query.deptId = id[0];
    };
    // 1-2基本信息条件
    let searchClick = function (params: any) {
      data.query.username = params.username;
      data.query.mobile = params.iphone;
      data.query.state = params.value;
    };

    let timer: any;
    watch(
      () => data.query,
      (newval: any, o: any) => {
        clearTimeout(timer);
        timer = setTimeout(() => {
          search();
        }, 500);
      },
      { deep: true }
    );

    // 修改用户状态
    let updateState = function (rowdata: any) {
      postUpdateState({
        username: rowdata.username,
        userId: rowdata.userId,
        state: rowdata.state === "PROHIBIT" ? "NORMAL" : "PROHIBIT",
      }).then((res: any) => {
        if (res.data.code === 200) {
          data.userdata.map((item: any) => {
            if (
              item.userId === rowdata.userId &&
              item.username === rowdata.username
            ) {
              Object.assign(item, {
                state: rowdata.state === "PROHIBIT" ? "NORMAL" : "PROHIBIT",
              });
            }
          });
        }
      });
    };

    provide("searchUser", search);
    return {
      ...toRefs(data),
      selectedClick,
      searchClick,
      updateState,
      userArr,
    };
  },
});
