
import {
  DownOutlined,
  SmileOutlined,
  FrownOutlined,
  FrownFilled,
} from "@ant-design/icons-vue";
import { defineComponent, reactive, ref, toRefs, watch } from "vue";
import { TreeDataItem } from "ant-design-vue/es/tree/Tree";

const treeData: TreeDataItem[] = [
  {
    title: "parent 1",
    key: "0-0",
    slots: {
      icon: "smile",
    },
    children: [
      { title: "leaf", key: "0-0-0", slots: { icon: "meh" } },
      { title: "leaf", key: "0-0-1", slots: { icon: "custom" } },
    ],
  },
];

export default defineComponent({
  props: ["frames"],
  name: "Framework",
  components: {
    DownOutlined,
    SmileOutlined,
    FrownOutlined,
    FrownFilled,
  },
  setup(props, ctx) {
    let data: any = reactive({
      selectedKeys: [],
      expandedKeys: [],
    });

    watch(
      () => data.selectedKeys,
      (nval, o) => {
        ctx.emit("selectedClick", nval);
      }
    );
    watch(
      () => props.frames,
      (nval, o) => {
        data.expandedKeys = [1];
      }
    );

    return {
      ...toRefs(data),
      treeData,
    };
  },
});
