
import { defineComponent, reactive, toRefs, watch } from "vue";
const plainOptions = [
  { label: "正常", value: "NORMAL" },
  { label: "停用", value: "PROHIBIT" },
  { label: "所有", value: null },
];
export default defineComponent({
  setup(props, ctx) {
    let data: any = reactive({
      username: "",
      iphone: "",
      value: null,
    });
    watch(data, (newval, o) => {
      ctx.emit("searchClick", newval);
    });
    return {
      ...toRefs(data),
      plainOptions,
    };
  },
});
