
import { defineComponent, inject, reactive, ref, toRefs, watch } from "vue";
import {
  getRoleList,
  postupdateuser,
  getAllDepartment,
} from "../../../../server/http/api/admin";

// import from '';
let options = [
  {
    value: "jack",
    label: "Jack",
  },
  {
    value: "lucy",
    label: "Lucy",
  },
  {
    value: "disabled",
    label: "Disabled",
    disabled: true,
  },
  {
    value: "yiminghe",
    label: "Yiminghe",
  },
];
export default defineComponent({
  props: ["userData", "userArr"],
  setup(props, ctx) {
    const searchUser: any = inject("searchUser");

    let data: any = reactive({
      userId: "",
      name: "",
      username: "",
      mobile: "",
      email: "",
      departmentIdLong: [],
      roleIdsLong: [],
      position: "",
      note: "",
      dingUserId: "",
    });
    let departmentDetail: any = ref([]);
    let rolesDetail: any = ref([]);

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    function init(arr: any) {
      let s: any = [];
      arr.map((item: any) => {
        s.push(item.value);
      });
      return s;
    }
    const updatedata = () => {
      visible.value = true;
      //console.log("待编辑信息", props.userData);

      // 获取角色下拉列表
      getRoleList({}).then((res: any) => {
        if (res.data.code === 200) {
          //console.log("获取角色下拉列表", res.data.data);

          res.data.data.map((item: any) => {
            rolesDetail.value.push({
              label: item.roleName,
              value: item.roleId * 1,
            });
          });
        }
      });
      //部门信息
      getAllDepartment().then((res: any) => {
        if (res.data.code === 200) {
          res.data.data.map((item: any) => {
            departmentDetail.value.push({
              label: item.name,
              value: item.id,
            });
          });
        }
      });
      data.userId = props.userData.userId;
      data.name = props.userData.name;
      data.username = props.userData.username;
      data.mobile = props.userData.mobile;
      data.email = props.userData.email;
      data.position = props.userData.position;
      data.note = props.userData.note;
      data.departmentIdLong = init(props.userData.department);
      data.roleIdsLong = init(props.userData.roles);
      data.dingUserId = props.userData.dingUserId;
    };

    const handleOk = (e: MouseEvent) => {
      confirmLoading.value = true;
      postupdateuser(data).then((res: any) => {
        if (res.data.code === 200) {
          searchUser();
        }
        visible.value = false;
        confirmLoading.value = false;
      });
    };

    const changeDepartment = () => {};
    const changeRoles = () => {};

    return {
      departmentDetail,
      rolesDetail,
      visible,
      ...toRefs(data),
      confirmLoading,
      handleOk,
      options,
      updatedata,
      changeDepartment,
      changeRoles,
    };
  },
});
