
import { defineComponent, inject, reactive, ref, toRefs, watch } from "vue";
import {
  getRoleList,
  addUser,
  getAllDepartment,
} from "@/server/http/api/admin";
import bus from "@/utils/bus";

// import from '';

export default defineComponent({
  props: ["userArr"],
  setup(props, ctx) {
    const searchUser: any = inject("searchUser");
    let data: any = reactive({
      name: "",
      username: "",
      mobile: "",
      email: "",
      roleIdsLong: [],
      departmentIdLong: [],
      position: "",
      note: "",
      dingUserId: "",
    });
    let departmentDetail: any = ref([]);
    let rolesDetail: any = ref([]);

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const updatedata = () => {
      visible.value = true;

      // 获取角色下拉列表
      getRoleList({}).then((res: any) => {
        if (res.data.code === 200) {
          //   //console.log("获取角色下拉列表", res.data.data);

          res.data.data.map((item: any) => {
            rolesDetail.value.push({
              label: item.roleName,
              value: item.roleId * 1,
            });
          });
        }
      });
      //部门信息
      getAllDepartment().then((res: any) => {
        if (res.data.code === 200) {
          res.data.data.map((item: any) => {
            departmentDetail.value.push({
              label: item.name,
              value: item.id,
            });
          });
        }
      });
    };

    const handleOk = (e: MouseEvent) => {
      confirmLoading.value = true;
      addUser(data).then((res: any) => {
        if (res.data.code === 200) {
          searchUser();
          data.username = "";
          data.mobile = "";
          data.email = "";
          data.roleIdsLong = [];
          data.departmentIdLong = [];
          data.position = "";
          data.note = "";
          data.dingUserId = "";
        }
        visible.value = false;
        confirmLoading.value = false;
      });
    };

    const changeDepartment = () => {};
    const changeRoles = () => {};

    return {
      departmentDetail,
      rolesDetail,
      visible,
      ...toRefs(data),
      confirmLoading,
      handleOk,
      updatedata,
      changeDepartment,
      changeRoles,
    };
  },
});
