
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";

import { defineComponent, inject } from "vue";
import { postResetPassword, userDelete } from "../../../server/http/api/admin";
import UpdateUser from "./modal/UpdateUser.vue";
const columns = [
  {
    title: "用户名称",
    key: "name",
    dataIndex: "name",
    slots: { customRender: "name" },
  },
  {
    dataIndex: "username",
    key: "username",
    title: "登入名称",
    slots: { customRender: "username" },
  },
  {
    title: "部门",
    dataIndex: "department",
    key: "department",
    slots: { customRender: "department" },
  },
  {
    title: "角色",
    dataIndex: "roles",
    key: "roles",
    slots: { customRender: "roles" },
  },
  // {
  //   title: "用户ID",
  //   key: "userId",
  //   dataIndex: "userId",
  //   slots: { customRender: "userId" },
  // },
  {
    title: "用户状态",
    key: "state",
    // dataIndex: "state",
    slots: { customRender: "state" },
  },
  {
    title: "手机号",
    dataIndex: "mobile",
    key: "mobile",
  },

  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

export default defineComponent({
  props: ["userlist", "userArr"],
  components: {
    SmileOutlined,
    DownOutlined,
    UpdateUser,
  },
  setup(props, ctx) {
    const searchUser: any = inject("searchUser");
    // 修改
    let resetpassword = function (rowdata: any) {
      // 重置密码
      postResetPassword({
        username: rowdata.username,
        userId: rowdata.userId,
      });
    };

    // 用户状态
    let switchClick = function (str: string) {
      ctx.emit("updateState", str);
    };
    function deleteUser(record: any) {
      userDelete(record.userId).then((res: any) => {
        if (res.data.code === 200) {
          searchUser();
        }
      });
    }
    return {
      columns,
      resetpassword,
      deleteUser,
      switchClick,
    };
  },
});
